}


vec2 laguerreL(vec2 z, int n) {
  vec2 l0 = vec2(1.0, 0.0);
  if (n == 0) return l0;
  vec2 l1 = vec2(1.0, 0.0) - z;
  if (n == 1) return l1;
  vec2 ln = l1;
  for (int k = 2; k <= 10; k++) {
    if (k > n) break;
    float fk = float(k);
    ln = ((2.0 * fk - 1.0 - z.x) * l1 - vec2(z.y * l1.y, -z.y * l1.x) - (fk - 1.0) * l0) / fk;
